124	    /// flock on the data file itself ineffective for protecting external readers.
125	    private func withFileLock<T>(mode: Int32, body: () throws -> T) async throws -> T {
126	        let fd = Darwin.open(lockPath, O_CREAT | O_RDWR, 0o644)
127	        guard fd >= 0 else { throw FileManagerError.cannotOpenLockFile(path: lockPath) }
128	        defer { Darwin.close(fd) }
129	
130	        let deadline = Date().addingTimeInterval(lockTimeoutSeconds)
131	        while flock(fd, mode | LOCK_NB) != 0 {
132	            guard Date() < deadline else {
133	                throw FileManagerError.lockTimeout(path: lockPath, timeoutSeconds: lockTimeoutSeconds)
134	            }
135	            try await Task.sleep(for: .milliseconds(50))
136	        }
137	        defer { flock(fd, LOCK_UN) }
138	
139	        return try body()
140	    }
