173	enum FileManagerError: Error, CustomStringConvertible {
174	    case cannotOpenLockFile(path: String)
175	    case lockTimeout(path: String, timeoutSeconds: Double)
176	
177	    var description: String {
178	        switch self {
179	        case let .cannotOpenLockFile(path):
180	            "Cannot open lock file at \(path)"
181	        case let .lockTimeout(path, secs):
182	            "Could not acquire flock on \(path) within \(secs)s"
183	        }
